const item = $input.first();
const json = item.json ?? {};
const attachments = [];

for (const [binaryKey, binaryFile] of Object.entries(item.binary ?? {})) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  attachments.push({
    name: binaryFile.fileName ?? binaryKey,
    sizeLabel: binaryFile.fileSize ?? 'Adjunto',
    mimeType: binaryFile.mimeType ?? 'application/octet-stream',
    previewUrl: `data:${binaryFile.mimeType ?? 'application/octet-stream'};base64,${buffer.toString('base64')}`
  });
}

const extractEmail = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return '';
  const match = raw.match(/<([^>]+)>/);
  return (match?.[1] ?? raw).trim().toLowerCase();
};

const htmlToText = (value) =>
  String(value ?? '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<li>/gi, '- ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\r/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/ {2,}/g, ' ')
    .trim();

const fromRaw = json.from ?? json.headers?.from ?? '';
const fromEmail = extractEmail(fromRaw);
const subject = String(json.subject ?? '');
const plainText = String(json.text ?? json.plainText ?? '').trim();
const html = String(json.html ?? '');
const htmlText = htmlToText(html);
const text = [plainText, htmlText].filter(Boolean).sort((a, b) => b.length - a.length)[0] ?? '';
const combined = `${subject}\n${text}`.toLowerCase();

const isPilotSelfMail = fromEmail === 'tsanjuan@innovexa.com.ar';
const looksLikeKingstonFlow = combined.includes('kingston') || fromEmail.endsWith('@kingston.com');

if (isPilotSelfMail || !looksLikeKingstonFlow) {
  return [];
}

return [{
  json: {
    from: fromRaw,
    fromEmail,
    subject,
    text,
    html,
    receivedAt: json.receivedAt ?? json.date ?? new Date().toISOString(),
    attachments
  }
}];

const emailItem = $('Normalizar correo Kingston').first().json;
const aiItem = $input.first().json;
const raw =
  aiItem.choices?.[0]?.message?.content ??
  aiItem.json ??
  aiItem.output ??
  aiItem.response ??
  aiItem.result ??
  aiItem.message?.content ??
  aiItem.text ??
  aiItem.content ??
  aiItem;

let parsed = raw;
if (typeof raw === 'string') {
  const cleaned = raw.replace(/^```json|^```|```$/gm, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : cleaned);
}

const sourceText = [emailItem.text, emailItem.html].filter(Boolean).join('\n\n');
const compact = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const matchOne = (regex) => compact(sourceText.match(regex)?.[1] ?? '');
const normalizedLines = sourceText
  .replace(/\r/g, '')
  .split('\n')
  .map((line) => compact(line))
  .filter(Boolean);
const fieldByLabel = {};
const canonicalize = (label) =>
  String(label ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
for (const line of normalizedLines) {
  const match = line.match(/^(Caso#?|Nombre|CUIL#?|Direcci[oó]n|Barrio|Ciudad|Estado|Pais|Pa[ií]s|Postal|Tel[eé]fono|Correo|Notas)\s*:\s*(.*)$/i);
  if (!match) continue;
  fieldByLabel[canonicalize(match[1])] = compact(match[2]);
}
const findQuantityAndSku = (label) => {
  const exact = sourceText.match(new RegExp(label + String.raw`\s*:\s*\((\d+)\)\s*([A-Z0-9./_-]+)`, 'i'));
  if (exact) {
    return { quantity: Number(exact[1]), sku: compact(exact[2]) };
  }
  const loose = sourceText.match(new RegExp(label + String.raw`\s*:\s*([A-Z0-9./_-]+)`, 'i'));
  return { quantity: undefined, sku: compact(loose?.[1] ?? '') };
};
const mailToMatch = sourceText.match(/mailto:([^\s>]+)/i);

const partData = findQuantityAndSku('Parte#?');
const replacementData = findQuantityAndSku('Reemplazo');
const extracted = {
  kingstonNumber: fieldByLabel['caso#'] || matchOne(/Caso#\s*:\s*([^\n]+)/i),
  contactName: fieldByLabel['nombre'] || matchOne(/Nombre\s*:\s*([^\n]+)/i),
  contactEmail: fieldByLabel['correo'] || compact(mailToMatch?.[1] ?? ''),
  contactPhone: fieldByLabel['telefono'] || matchOne(/Tel[eé]fono\s*:\s*([^\n]+)/i),
  addressLine: fieldByLabel['direccion'] || matchOne(/Direcci[oó]n\s*:\s*([^\n]+)/i),
  neighborhood: fieldByLabel['barrio'] || matchOne(/Barrio\s*:\s*([^\n]+)/i),
  city: fieldByLabel['ciudad'] || matchOne(/Ciudad\s*:\s*([^\n]+)/i),
  province: fieldByLabel['estado'] || matchOne(/Estado\s*:\s*([^\n]+)/i),
  country: fieldByLabel['pais'] || matchOne(/Pa[ií]s\s*:\s*([^\n]+)/i),
  postalCode: fieldByLabel['postal'] || matchOne(/Postal\s*:\s*([^\n]+)/i),
  notes: fieldByLabel['notas'] || '',
  quantity: partData.quantity ?? replacementData.quantity,
  sku: partData.sku,
  replacementSku: replacementData.sku
};

const isValidEmail = (value) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(value ?? '').trim());
const normalizeText = (...values) => values.filter(Boolean).join(' ').toLowerCase();
const geographyHint = normalizeText(extracted.city, extracted.province, extracted.addressLine, emailItem.text);
const capitalHints = ['caba', 'capital federal', 'ciudad autonoma de buenos aires', 'ciudad autónoma de buenos aires'];
const zone = capitalHints.some((hint) => geographyHint.includes(hint)) ? 'Capital / AMBA' : 'Interior / Gran Buenos Aires';
const deliveryMode = zone === 'Capital / AMBA' ? 'Pickup' : 'Dispatch';
const priorities = ['Low', 'Medium', 'High', 'Critical'];
const priority = priorities.includes(parsed.priority) ? parsed.priority : 'Medium';
const quantity = Number.isFinite(extracted.quantity) && extracted.quantity > 0 ? extracted.quantity : (parsed.quantity > 0 ? parsed.quantity : 1);
const sku = extracted.sku || parsed.sku || extracted.replacementSku || 'SKU pendiente';
const replacementSku = extracted.replacementSku || parsed.replacementSku || sku;
const addressParts = [extracted.addressLine, extracted.neighborhood].filter((value) => value && value !== '-----');
const address = addressParts.join(', ') || compact(parsed.address) || 'Direccion pendiente de confirmar';
const city = extracted.city || compact(parsed.city) || 'Ciudad pendiente de confirmar';
const province = extracted.province || compact(parsed.province) || 'Provincia pendiente de confirmar';
const contactName = extracted.contactName || compact(parsed.contactName) || compact(parsed.clientName) || 'Cliente Kingston';
const clientName = compact(parsed.clientName) || contactName;
const contactEmail = isValidEmail(extracted.contactEmail)
  ? extracted.contactEmail.replace(/<.*$/, '')
  : isValidEmail(parsed.contactEmail)
    ? parsed.contactEmail
    : `pendiente-rma-${(extracted.kingstonNumber || parsed.kingstonNumber || 'sin-ticket').toLowerCase()}@kingestion.local`;
const contactPhone = extracted.contactPhone || compact(parsed.contactPhone) || 'Pendiente de confirmar';
const productDescription = compact(parsed.productDescription) || `Producto Kingston ${sku}`;
const failureDescription = extracted.notes || compact(parsed.failureDescription) || 'Pendiente de detalle informado por Kingston';
const nextAction = compact(parsed.nextAction) || (zone === 'Interior / Gran Buenos Aires'
  ? 'Contactar al cliente para coordinar envio del producto fallado.'
  : 'Contactar al cliente y validar disponibilidad para la gestion del reemplazo.');
const rawObservations = typeof parsed.observations === 'string' ? parsed.observations.trim() : '';
const cleanedObservations = rawObservations.replace(/Se infiri[oó] la zona[^.]*\.\s*/i, '').trim();
const attachmentNames = (emailItem.attachments ?? []).map((attachment) => attachment.name).join(' ');
const rawIntent = typeof parsed.mailIntent === 'string' ? parsed.mailIntent.trim().toLowerCase() : '';
const proofHintText = normalizeText(emailItem.subject, emailItem.text, attachmentNames, parsed.proofReason, rawIntent);
const heuristicProof = Boolean(emailItem.attachments?.length) && /(comprobante|transferencia|pago|reintegro|deposito|depósito|ticket|correo argentino|oca|andreani|captura|comision|envio|envío)/i.test(proofHintText);
const containsPaymentProof = parsed.containsPaymentProof === true || rawIntent === 'payment_proof' || rawIntent === 'mixed' || heuristicProof;
const mailIntent = ['new_case', 'follow_up', 'payment_proof', 'mixed'].includes(rawIntent)
  ? rawIntent
  : containsPaymentProof
    ? 'payment_proof'
    : 'new_case';
const attachments = (emailItem.attachments ?? []).map((attachment) => ({
  ...attachment,
  kind: containsPaymentProof ? 'proof' : attachment.kind
}));
const proofReason = typeof parsed.proofReason === 'string' ? parsed.proofReason.trim() : '';
const automationNotes = [
  'Zona normalizada por automatizacion: ' + zone + '.'
];
const missingFields = [];
if (!isValidEmail(extracted.contactEmail) && !isValidEmail(parsed.contactEmail)) missingFields.push('correo del end user');
if (!extracted.contactPhone && !parsed.contactPhone) missingFields.push('telefono');
if (!extracted.addressLine && !parsed.address) missingFields.push('direccion');
if (!extracted.city && !parsed.city) missingFields.push('ciudad');
if (!extracted.province && !parsed.province) missingFields.push('provincia');
if (!extracted.notes && !parsed.failureDescription) missingFields.push('detalle de falla');

if (missingFields.length) {
  automationNotes.push('Campos faltantes completados con placeholders operativos: ' + missingFields.join(', ') + '.');
}

if (containsPaymentProof) {
  automationNotes.push('IA detecto un posible comprobante de pago o reintegro en este correo.');
}

if (proofReason) {
  automationNotes.push('Motivo IA: ' + proofReason);
}

const observations = [cleanedObservations, ...automationNotes].filter(Boolean).join(' ');
const updateComment = containsPaymentProof
  ? 'n8n detecto un comprobante de pago o reintegro y lo adjunto automaticamente al caso para revision interna.'
  : 'n8n detecto un nuevo correo de autorizacion o seguimiento de Kingston y lo agrego al caso.';

return [{
  json: {
    ...parsed,
    kingstonNumber: extracted.kingstonNumber || parsed.kingstonNumber || 'SIN-TICKET',
    clientName,
    contactName,
    contactEmail,
    contactPhone,
    zone,
    deliveryMode,
    priority,
    address,
    province,
    city,
    sku,
    quantity,
    productDescription,
    failureDescription,
    nextAction,
    observations,
    origin: 'Kingston email',
    externalStatus: 'Informado',
    replacementSku,
    attachments,
    primaryAttachment: attachments[0] ?? null,
    containsPaymentProof,
    mailIntent,
    proofReason,
    updateComment,
    _emailContext: emailItem
  }
}];

