={{ JSON.stringify($json.count > 0 ? (() => {
  const payload = $('Consolidar payload del caso').first().json;
  const nextBody = {
    comment: {
      body: payload.updateComment,
      internal: true
    }
  };

  if (payload.primaryAttachment) {
    nextBody.attachment = payload.primaryAttachment;
  }

  return nextBody;
})() : $('Consolidar payload del caso').first().json) }}

