const caseItem = $('Consolidar payload del caso').first().json;
const searchResult = $('Buscar caso por ticket Kingston').first().json;
const wasExisting = searchResult.count > 0;
const existingCase = searchResult.items?.[0] ?? null;
const emailContext = caseItem._emailContext ?? {};

const extractEmail = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return '';
  const match = raw.match(/<([^>]+)>/);
  return (match?.[1] ?? raw).trim();
};

const buildPilotEnvelope = ({ destinationEmail, subject, text }) => ({
  toEmail: 'tsanjuan@innovexa.com.ar',
  originalToEmail: destinationEmail,
  subject: `[PILOTO] ${subject}`,
  text: `${text}\n\nDestino real previsto: ${destinationEmail}`
});

const signature = 'Saludos cordiales,\n\nEquipo de RMA ANYX\nconsultaskingston@anyx.com.ar\nTel: 4815-4614';
const senderEmail = extractEmail(emailContext.from).toLowerCase();
const originalKingston = senderEmail || 'rma@kingston.com';
const contactName = existingCase?.contactName || caseItem.contactName || 'cliente';
const pickupAddress = 'Avenida San Isidro Labrador 4471 (C.A.B.A.)';
const internalDomains = ['@anyx.com.ar', '@innovexa.com.ar', '@kingston.com'];
const isInternalSender = internalDomains.some((domain) => senderEmail.endsWith(domain));

if (wasExisting) {
  const replyDestination = senderEmail || (existingCase?.contactEmail ?? '').trim();
  const currentStatus = existingCase?.externalStatus ?? caseItem.externalStatus;
  const statusReplyMap = {
    'Informado': `Su caso esta recibido y en proceso de solucion. Tiempo aproximado entre 5 y 45 dias habiles desde que recibio el primer mail informandole sobre el comienzo del tramite.\n\n${signature}`,
    'Aviso de envio': `A la espera de recepcion del producto fallado enviado por Ud. Si aun no lo ha enviado por favor seguir las instrucciones enviadas en mail anterior. Muchas gracias.\n\n${signature}`,
    'Producto recepcionado y en preparacion': `Hemos recibido su producto fallado y estamos en proceso de enviarle el cambio correspondiente en caso de contar con disponibilidad local. Tendra una actualizacion sobre su caso durante el transcurso de los proximos 10 dias habiles.\n\n${signature}`,
    'Pedido deposito y etiquetado': `Producto en Anyx, en preparacion. En los proximos 5 dias habiles tendra novedades sobre el estado de su caso.\n\n${signature}`,
    'Pedido Kingston': `El producto nuevo necesario para cumplir con el cambio en gtia. NO se encuentra disponible en Argentina, por lo que ha sido solicitado a KINGSTON en EEUU. Le avisaremos por este medio cuando arribe a la Argentina en un plazo aproximado de 10 dias habiles.\n\n${signature}`,
    'Producto enviado': `Su reemplazo ha sido enviado. Corrobore con el Expreso el estado de su envio, los datos de su envio han sido enviados por e-mail.\n\n${signature}`,
    'Producto listo para retiro': `El producto/s esta/n listo/s para su retiro. Podra pasar a realizar el cambio los dias Lunes, Miercoles o Viernes (EXCEPTO FERIADOS) de 9 a 17 hs por ${pickupAddress}. Por favor recuerde traer el/los producto/s fallado/s.\n\n${signature}`,
    'Realizado': `Producto cambiado con exito. RMA finalizado. Gracias por confiar en KINGSTON.\n\n${signature}`,
    'Vencido': `Caso VENCIDO ya que ha pasado el tiempo estipulado para obtener una respuesta de su parte. Si aun desea tramitar el cambio debera volver a generar una nueva solicitud de RMA ante KINGSTON.\n\n${signature}`,
    'Cerrado': `Caso CERRADO por parte de KINGSTON. Cualquier consulta comunicarse nuevamente con KINGSTON.\n\n${signature}`,
    'OV creada': null,
    'Liberar mercaderia': `Producto en preparacion. En los proximos 5 dias habiles tendra novedades sobre el estado de su caso.\n\n${signature}`,
    'Pendiente de recibirlo': `Su caso continua en gestion operativa a la espera de la siguiente confirmacion interna. Le avisaremos por este medio apenas tengamos novedades.\n\n${signature}`,
    'Pedido guia': `Su caso se encuentra en coordinacion final de despacho. Apenas este disponible la guia definitiva se la informaremos por este medio.\n\n${signature}`
  };

  if (!replyDestination || isInternalSender) {
    return [];
  }

  const replyText = statusReplyMap[currentStatus] ?? null;
  if (!replyText) {
    return [];
  }

  return [{
    json: buildPilotEnvelope({
      destinationEmail: replyDestination,
      subject: `ANYX | Estado de su caso ${existingCase?.kingstonNumber ?? caseItem.kingstonNumber}`,
      text: replyText
    })
  }];
}

const emails = [
  buildPilotEnvelope({
    destinationEmail: originalKingston,
    subject: `ANYX | Caso ${caseItem.kingstonNumber} recibido`,
    text: `Se recibio y dio de alta el caso ${caseItem.kingstonNumber} en Kingestion para ${caseItem.clientName}.`
  })
];

const customerText = caseItem.zone === 'Interior / Gran Buenos Aires'
  ? `Hola ${contactName}. Recibimos la autorizacion de Kingston para el caso ${caseItem.kingstonNumber}. Por favor envia el producto fallado a ANYX y responde este correo con el comprobante y los datos bancarios para el reintegro.`
  : `Hola ${contactName}. Recibimos la autorizacion de Kingston para el caso ${caseItem.kingstonNumber}. El equipo de ANYX ya esta validando stock y proximo paso. Te vamos a mantener informado desde Kingestion.`;

if (caseItem.contactEmail) {
  emails.push(
    buildPilotEnvelope({
      destinationEmail: caseItem.contactEmail,
      subject: `ANYX | ${caseItem.zone === 'Interior / Gran Buenos Aires' ? 'Instrucciones de envio' : 'Caso en validacion'} para ${caseItem.kingstonNumber}`,
      text: customerText
    })
  );
}

return emails.map((email) => ({ json: email }));

const control = $input.first().json;

if (control.control?.paused) {
  return [];
}

return [{
  json: {
    ...$('Normalizar correo Kingston').first().json,
    _automationControl: control
  }
}];
